// ── ASSETS — JPG base64 (createImage, JPEG soportado) ─────────────────────────
function _b64(s) {
  const raw = atob(s);
  const a = new Uint8Array(raw.length);
  for (let i = 0; i < raw.length; i++) a[i] = raw.charCodeAt(i);
  return a;
}

const A_NEWS = [
  "",
  "",
  "",
];


// ── HELPERS ───────────────────────────────────────────────────────────────────
function rgb(hex) {
  return {
    r: parseInt(hex.substring(0,2),16)/255,
    g: parseInt(hex.substring(2,4),16)/255,
    b: parseInt(hex.substring(4,6),16)/255,
  };
}
const fill   = (hex) => [{ type:"SOLID", color:rgb(hex) }];
const stroke = (hex) => [{ type:"SOLID", color:rgb(hex) }];

function rect(parent, x, y, w, h, hexFill, opts={}) {
  const r = figma.createRectangle();
  r.x=x; r.y=y; r.resize(w,h);
  r.fills = hexFill ? fill(hexFill) : [];
  if (opts.stroke)  { r.strokes=stroke(opts.stroke); r.strokeWeight=opts.sw||1; r.strokeAlign="INSIDE"; }
  if (opts.radius)  r.cornerRadius=opts.radius;
  if (opts.opacity) r.opacity=opts.opacity;
  parent.appendChild(r);
  return r;
}

// Coloca un SVG como nodo vectorial (createNodeFromSvg)
function svgNode(parent, svgStr, x, y, w, h) {
  const node = figma.createNodeFromSvg(svgStr);
  node.resize(w, h);
  node.x = x;
  node.y = y;
  parent.appendChild(node);
  return node;
}

// Coloca una imagen JPEG (base64) como rectángulo con fill IMAGE
function jpgRect(parent, x, y, w, h, b64data, opts={}) {
  const hash = figma.createImage(_b64(b64data)).hash;
  const r = figma.createRectangle();
  r.x=x; r.y=y; r.resize(w,h);
  r.fills = [{ type:"IMAGE", scaleMode:"FILL", imageHash:hash }];
  if (opts.radius) r.cornerRadius=opts.radius;
  parent.appendChild(r);
  return r;
}

async function txt(parent, x, y, chars, font, size, hexColor, opts={}) {
  await figma.loadFontAsync(font);
  const t = figma.createText();
  t.fontName=font; t.fontSize=size; t.characters=chars;
  t.fills=fill(hexColor); t.x=x; t.y=y;
  if (opts.w)       { t.textAutoResize="HEIGHT"; t.resize(opts.w,t.height); }
  if (opts.align)   t.textAlignHorizontal=opts.align;
  if (opts.opacity) t.opacity=opts.opacity;
  parent.appendChild(t);
  return t;
}

function frame(parent, name, x, y, w, h, hexFill) {
  const f = figma.createFrame();
  f.name=name; f.x=x; f.y=y; f.resize(w,h);
  f.fills = hexFill ? fill(hexFill) : [{ type:"SOLID", color:{r:1,g:1,b:1} }];
  f.clipsContent=false;
  if (parent) parent.appendChild(f);
  return f;
}

// ── VALIDAR PÁGINA ────────────────────────────────────────────────────────────
function validatePages() {
  const log   = [];
  const names = [...figma.root.children].map(p => p.name);
  if (names.includes(HOME_PAGE)) {
    log.push("✅ " + HOME_PAGE + " ya existe");
  } else {
    const p = figma.createPage(); p.name = HOME_PAGE;
    log.push("➕ Creada: " + HOME_PAGE);
  }
  return log;
}

// ── SECTION HEADING ───────────────────────────────────────────────────────────
async function sectionHeading(F, y, eyebrow, title, sub, centered=false) {
  const tx  = centered ? (1440-640)/2 : CX;
  const tw  = 640;
  const al  = centered ? "CENTER" : "LEFT";
  const ttw = centered ? 640 : CW;
  await txt(F, tx, y, eyebrow.toUpperCase(), BOLD, 13, BORGONA, { w:tw, align:al });
  y += 24;
  await txt(F, tx, y, title, BOLD, 40, GRIS, { w:ttw, align:al });
  y += 56;
  if (sub) {
    await txt(F, tx, y, sub, REGULAR, 17, GRIS_CAPTION, { w:ttw, align:al });
    y += 38;
  }
  return y;
}

