// ── BUILD HOME ────────────────────────────────────────────────────────────────
async function buildHOME() {
  const page = figma.root.children.find(p => p.name === HOME_PAGE);
  if (!page) throw new Error("Página '" + HOME_PAGE + "' no encontrada.");
  figma.currentPage = page;
  page.findChildren(n => n.name === "HOME — TIM").forEach(n => n.remove());
  const F = frame(page, "HOME — TIM", 0, 0, 1440, 100, BLANCO);
  let y = 0;
  y = await _navbar(F, y);
  y = await _hero(F, y);
  y = await _servicios(F, y);
  y = await _pasos(F, y);
  y = await _destacados(F, y);
  y = await _footer(F, y);
  F.resize(1440, y);
  figma.viewport.scrollAndZoomIntoView([F]);
  return "✅ HOME construida — " + y + "px";
}

// ── ENTRY POINT ───────────────────────────────────────────────────────────────
figma.showUI(__html__, { width:420, height:520, title:"TIM — HOME" });

figma.ui.onmessage = async (msg) => {
  const post = (t) => figma.ui.postMessage({ type:"log", text:t });
  if (msg.type === "run") {
    try {
      post("⏳ Cargando fuentes...");
      await figma.loadFontAsync(BOLD);
      await figma.loadFontAsync(SEMIBOLD);
      await figma.loadFontAsync(REGULAR);
      post("✅ Fuentes OK");
      post("");
      post("── Paso 1: Validando página ──");
      validatePages().forEach(l => post(l));
      post("");
      post("── Paso 2: Construyendo HOME ──");
      post("   Navbar...");
      post("   Hero + búsqueda...");
      post("   Servicios (5 cards + íconos SVG)...");
      post("   Cómo usar TIM (3 pasos + íconos SVG)...");
      post("   Destacados (3 cards + fotos)...");
      post("   Footer...");
      post(await buildHOME());
      post("");
      post("🎉 HOME lista en: " + HOME_PAGE);
      figma.ui.postMessage({ type:"done" });
      figma.notify("✅ HOME TIM generada!", { timeout:4000 });
    } catch(err) {
      figma.ui.postMessage({ type:"error", text:err.message });
      figma.notify("❌ " + err.message, { error:true });
      console.error(err);
    }
  }
  if (msg.type === "close") figma.closePlugin();
};
